Here's a fully functional Kanban board in a single HTML file using vanilla JavaScript, Tailwind CSS via CDN, with all the requested features:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Vibrant Kanban Board</title>
    <!-- Tailwind CSS via CDN -->
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        /* Custom styles for transitions and confetti */
        .card {
            transition: transform 0.3s ease, box-shadow 0.2s ease;
        }
        .card-moving {
            opacity: 0.5;
            transform: scale(0.98);
        }
        .confetti {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            pointer-events: none;
            z-index: 9999;
            background: #000;
        }
        .confetti-particle {
            position: absolute;
            background: hsl(0, 70%, 50%);
            border-radius: 2px;
            box-shadow: 0 0 10px rgba(0,0,0,0.2);
            animation: confetti 3s linear infinite;
        }
        @keyframes confetti {
            0% { transform: translate(0, -100vh) rotate(0deg); opacity: 1; }
            100% { transform: translate(0, 100vh) rotate(720deg); opacity: 0; }
        }
        /* Delete confirmation modal */
        .delete-modal {
            backdrop-filter: blur(5px);
            transition: opacity 0.3s ease;
        }
        .delete-modal.hidden {
            display: none;
        }
    </style>
</head>
<body class="bg-gradient-to-br from-purple-100 to-indigo-200 min-h-screen p-4 md:p-8">
    <!-- Confetti container -->
    <div id="confetti" class="confetti"></div>

    <!-- Kanban Board Container -->
    <div class="max-w-6xl mx-auto bg-white rounded-xl shadow-lg overflow-hidden">
        <h1 class="text-2xl font-bold text-center py-4 text-indigo-800">Vibrant Kanban Board</h1>
